                            Id = 1,
                            Anio = 2010,
                            Descripcion = "Inception (titulada: Origen en España y El origen en Hispanoamérica) es una película británica/estadounidense/canadiense/japonesa de ciencia ficción escrita, producida y dirigida por Christopher Nolan y protagonizada por Leonardo DiCaprio, Elliot Page, Joseph Gordon-Levitt, Ken Watanabe, Tom Hardy, Marion Cotillard, Cillian Murphy, Tom Berenger y Michael Caine. Se estrenó en Londres el 9 de julio de 2010. Recibió cuatro premios Óscar (mejor fotografía, mejor mezcla de sonido, mejor edición de sonido y mejores efectos visuales) y otras cuatro nominaciones (mejor película, mejor banda sonora, mejor guion original y mejor dirección artística). Además, obtuvo el tercer lugar de taquilla en 2010, según la ABC.",
                            Director = "Guy Hendrix Dyas",
                            Duracion = 148,
                            PosterUrl = "https://upload.wikimedia.org/wikipedia/en/2/2e/Inception_%282010%29_theatrical_poster.jpg",
                            PuntuacionMedia = 4.1m,
